{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$demo": {
    "previewSize": {
      "width": 375,
      "height": 812
    }
  },
  "title": "课后服务 - 手机版配置",
  "type": "object",
  "properties": {
    "serviceTitle": {
      "type": "string",
      "title": "服务标题",
      "description": "课后服务包名称",
      "default": "全年系统包-L1"
    },
    "field": {
      "type": "string",
      "title": "功能图标",
      "default": "https://uiweb.oss-cn-chengdu.aliyuncs.com/img/学习页/课后/icon.png",
      "format": "image",
      "ui:options": {
        "category": "设计"
      }
    }
  },
  "required": []
}

/* 重置默认边距 */
* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

.page-wrapper {
  width: 100%;
  min-height: 100vh;
  background-color: #ffffff;
  display: flex;
  flex-direction: column;
  overflow: hidden;
  font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
  height: 100vh;
  max-width: 375px;
  margin: 0 auto;
}

/* 导航栏 */
.nav-bar {
  width: 100%;
  flex-shrink: 0;
}

.nav-image {
  width: 100%;
  height: auto;
  display: block;
}

/* 主要内容区域 */
.main-content {
  flex: 1;
  padding: 0 20px;
  display: flex;
  flex-direction: column;
  gap: 24px;
  margin-top: 20px;
  overflow-y: auto;
}

/* Banner 广告图 */
.banner-wrapper {
  width: 100%;
  height: 112px;
  border-radius: 10px;
  overflow: hidden;
  flex-shrink: 0;
}

.banner-image {
  width: 100%;
  height: 100%;
  object-fit: cover;
  display: block;
}

/* 服务内容区域 */
.service-section {
  display: flex;
  flex-direction: column;
  gap: 14px;
}

/* 标题区 */
.title-row {
  display: flex;
  align-items: center;
  justify-content: space-between;
  width: 100%;
}

.service-title {
  font-size: 20px;
  font-weight: 500;
  color: #4d4d4d;
  font-family: "PingFang SC", sans-serif;
}

.teacher-info {
  display: flex;
  align-items: center;
  gap: 4px;
}

.teacher-label {
  font-size: 14px;
  color: #666666;
  font-family: "PingFang SC", sans-serif;
}

.teacher-avatar {
  width: 24px;
  height: 24px;
  border-radius: 9px;
  background-color: #fcda00;
  display: block;
}

/* 功能入口列表 */
.feature-list {
  display: flex;
  flex-direction: column;
  gap: 7px;
}

.feature-card {
  width: 100%;
  height: 64px;
  background-color: #fff3eb;
  border-radius: 18px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 0 20px;
}

.feature-left {
  display: flex;
  align-items: center;
  gap: 8px;
  flex: 1;
  min-width: 0;
}

.feature-icon {
  width: 36px;
  height: 36px;
  border-radius: 10.5px;
  flex-shrink: 0;
  display: block;
}

.feature-name {
  font-size: 16px;
  font-weight: 500;
  color: #6b2d03;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  font-family: "PingFang SC", sans-serif;
}

.feature-right {
  display: flex;
  align-items: center;
  gap: 4px;
  flex-shrink: 0;
  margin-left: 8px;
}

.feature-status {
  font-size: 14px;
  color: #e35b00;
  white-space: nowrap;
  font-family: "PingFang SC", sans-serif;
}

.chevron-icon {
  width: 16px;
  height: 16px;
  flex-shrink: 0;
}

.chevron-gray {
  color: #e0dfdf;
}

/* 底部链接 */
.bottom-link {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 4px;
  margin-top: 10px;
}

.bottom-link-text {
  font-size: 14px;
  color: #b2b2b2;
  font-family: "PingFang SC", sans-serif;
}

/* 底部指示条 */
.bottom-indicator {
  width: 100%;
  height: 34px;
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
}

.indicator-bar {
  width: 134px;
  height: 5px;
  background-color: #000000;
  border-radius: 9999px;
}

{
  "description": "课后服务手机版原型",
  "previewSize": {
    "width": 375,
    "height": 812
  },
  "configFields": [
    "serviceTitle"
  ]
}

import { ChevronRight } from 'lucide-react';

interface DemoProps {
  /** 课后服务包名称（页面级配置） */
  serviceTitle?: string;
  /** 手机和平板共用的广告图（项目级配置） */
  bannerImage?: string;
}

export default function PhoneAfterSchool({
  serviceTitle = '全年系统包-L1',
  bannerImage = 'https://uiweb.oss-cn-chengdu.aliyuncs.com/img/学习页/课后/banner.png',
}: DemoProps) {
  const features = [
    {
      name: '学习报告',
      status: '3篇报告未读',
      icon: 'https://uiweb.oss-cn-chengdu.aliyuncs.com/img/学习页/课后/icon.png',
    },
    {
      name: '活动挑战',
      status: '',
      icon: 'https://uiweb.oss-cn-chengdu.aliyuncs.com/img/学习页/课后/icon-1.png',
    },
    {
      name: '趣味复习',
      status: '',
      icon: 'https://uiweb.oss-cn-chengdu.aliyuncs.com/img/学习页/课后/icon-2.png',
    },
  ];

  return (
    <div
      className="w-full min-h-screen bg-white flex flex-col overflow-hidden"
      style={{
        fontFamily:
          '-apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif',
        height: '100vh',
        maxWidth: 375,
        margin: '0 auto',
      }}
    >
      {/* 状态栏 & 导航栏 */}
      <div className="w-full flex-shrink-0">
        <img
          src="https://uiweb.oss-cn-chengdu.aliyuncs.com/img/学习页/课后/手机/原生/导航&状态.png"
          alt="nav-status"
          className="w-full h-auto"
        />
      </div>

      {/* 主要内容区域 */}
      <div className="flex-1 px-5 flex flex-col gap-6 mt-5 overflow-y-auto">
        {/* Banner 广告图 */}
        <div className="w-full h-[112px] rounded-[10px] overflow-hidden flex-shrink-0">
          <img
            src={bannerImage}
            alt="banner"
            className="w-full h-full object-cover"
          />
        </div>

        {/* 服务内容 */}
        <div className="flex flex-col gap-[14px]">
          {/* 标题区 */}
          <div className="flex items-center justify-between w-full">
            <span
              className="text-[20px] font-medium text-[#4d4d4d]"
              style={{ fontFamily: '"PingFang SC", sans-serif' }}
            >
              {serviceTitle}
            </span>
            <div className="flex items-center gap-1">
              <span
                className="text-[14px] text-[#666666]"
                style={{ fontFamily: '"PingFang SC", sans-serif' }}
              >
                苹果指导师
              </span>
              <img
                src="https://uiweb.oss-cn-chengdu.aliyuncs.com/img/学习页/课后/指导师头像.png"
                alt="teacher"
                className="w-6 h-6 rounded-[9px]"
                style={{ backgroundColor: '#fcda00' }}
              />
            </div>
          </div>

          {/* 功能入口列表 */}
          <div className="flex flex-col gap-[7px]">
            {features.map((feature, index) => (
              <div
                key={index}
                className="w-full h-16 bg-[#fff3eb] rounded-[18px] flex items-center justify-between px-5"
              >
                <div className="flex items-center gap-2 flex-1 min-w-0">
                  <img
                    src={feature.icon}
                    alt=""
                    className="w-9 h-9 rounded-[10.5px] flex-shrink-0"
                  />
                  <span
                    className="text-[16px] font-medium text-[#6b2d03] truncate"
                    style={{ fontFamily: '"PingFang SC", sans-serif' }}
                  >
                    {feature.name}
                  </span>
                </div>
                <div className="flex items-center gap-1 flex-shrink-0 ml-2">
                  {feature.status && (
                    <span
                      className="text-[14px] text-[#e35b00] whitespace-nowrap"
                      style={{ fontFamily: '"PingFang SC", sans-serif' }}
                    >
                      {feature.status}
                    </span>
                  )}
                  <ChevronRight className="w-4 h-4 text-[#ffa66b]" />
                </div>
              </div>
            ))}
          </div>

          {/* 底部链接 */}
          <div className="flex items-center justify-center gap-1 mt-2.5">
            <span
              className="text-[14px] text-[#b2b2b2]"
              style={{ fontFamily: '"PingFang SC", sans-serif' }}
            >
              查看往期课程服务
            </span>
            <ChevronRight className="w-4 h-4 text-[#e0dfdf]" />
          </div>
        </div>
      </div>

      {/* 底部指示条 */}
      <div className="w-full h-[34px] flex items-center justify-center flex-shrink-0">
        <div className="w-[134px] h-[5px] bg-black rounded-full" />
      </div>
    </div>
  );
}

