  "$demo": {
    "previewSize": {
      "width": 1133,
      "height": 768
    }
  },
  "title": "课后服务 - 平板版配置",
  "type": "object",
  "properties": {}
}

/* 重置默认边距 */
* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

.page-wrapper {
  width: 100%;
  min-height: 100vh;
  background-color: #ffffff;
  display: flex;
  flex-direction: column;
  overflow: hidden;
  font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
  height: 100vh;
  max-width: 1133px;
  margin: 0 auto;
}

/* 导航栏 */
.nav-bar {
  width: 100%;
  flex-shrink: 0;
}

.nav-image {
  width: 100%;
  height: auto;
  display: block;
}

/* 主要内容区域 */
.main-content {
  flex: 1;
  padding: 0 137px;
  display: flex;
  flex-direction: column;
  gap: 40px;
  margin-top: 20px;
  overflow-y: auto;
}

/* Banner 广告图 */
.banner-wrapper {
  width: 100%;
  height: 112px;
  border-radius: 10px;
  overflow: hidden;
  flex-shrink: 0;
}

.banner-image {
  width: 100%;
  height: 100%;
  object-fit: cover;
  display: block;
}

/* 服务内容区域 */
.service-section {
  display: flex;
  flex-direction: column;
  gap: 24px;
}

/* 标题区 */
.title-row {
  display: flex;
  align-items: center;
  justify-content: space-between;
  width: 100%;
}

.service-title {
  font-size: 22.5px;
  font-weight: 500;
  color: #4d4d4d;
  font-family: "PingFang SC", sans-serif;
}

.teacher-info {
  display: flex;
  align-items: center;
  gap: 5px;
}

.teacher-label {
  font-size: 17.5px;
  color: #666666;
  font-family: "PingFang SC", sans-serif;
}

.teacher-avatar {
  width: 30px;
  height: 30px;
  border-radius: 11.25px;
  background-color: #fcda00;
  display: block;
}

/* 功能入口列表 */
.feature-list {
  display: flex;
  flex-direction: column;
  gap: 20px;
}

.feature-row {
  display: flex;
  gap: 20px;
  width: 100%;
}

.feature-card {
  flex: 1;
  height: 80px;
  background-color: #fff3eb;
  border-radius: 22.5px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 0 25px;
}

.feature-card-full {
  flex: 0 0 100%;
}

.feature-left {
  display: flex;
  align-items: center;
  gap: 10px;
  flex: 1;
  min-width: 0;
}

.feature-icon {
  width: 45px;
  height: 45px;
  border-radius: 13.125px;
  flex-shrink: 0;
  display: block;
}

.feature-name {
  font-size: 20px;
  font-weight: 500;
  color: #6b2d03;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  font-family: "PingFang SC", sans-serif;
}

.feature-right {
  display: flex;
  align-items: center;
  gap: 5px;
  flex-shrink: 0;
  margin-left: 8px;
}

.feature-status {
  font-size: 17.5px;
  color: #e35b00;
  white-space: nowrap;
  font-family: "PingFang SC", sans-serif;
}

.chevron-icon {
  width: 20px;
  height: 20px;
  flex-shrink: 0;
}

.chevron-gray {
  color: #e0dfdf;
}

/* 底部链接 */
.bottom-link {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 4px;
  margin-top: 20px;
}

.bottom-link-text {
  font-size: 17.5px;
  color: #b2b2b2;
  font-family: "PingFang SC", sans-serif;
}

{
  "previewSize": {
    "width": 1133,
    "height": 768
  },
  "bindings": {
    "project": [
      "bannerImage"
    ]
  }
}

import { ChevronRight } from 'lucide-react';

interface DemoProps {}

export default function PadAfterSchool(props: DemoProps) {
  const { bannerImage = 'https://uiweb.oss-cn-chengdu.aliyuncs.com/img/学习页/课后/banner.png' } = props as Record<string, unknown>;
  const featureRows = [
    [
      {
        name: '学习报告',
        status: '3篇报告未读',
        icon: 'https://uiweb.oss-cn-chengdu.aliyuncs.com/img/学习页/课后/icon.png',
      },
      {
        name: '活动挑战',
        status: '',
        icon: 'https://uiweb.oss-cn-chengdu.aliyuncs.com/img/学习页/课后/icon-1.png',
      },
    ],
    [
      {
        name: '随堂故事',
        status: '',
        icon: 'https://uiweb.oss-cn-chengdu.aliyuncs.com/img/学习页/课后/icon-2.png',
      },
    ],
  ];

  return (
    <div
      className="w-full min-h-screen bg-white flex flex-col overflow-hidden"
      style={{
        fontFamily:
          '-apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif',
        height: '100vh',
        maxWidth: 1133,
        margin: '0 auto',
      }}
    >
      {/* 状态栏 & 导航栏 */}
      <div className="w-full flex-shrink-0">
        <img
          src="https://uiweb.oss-cn-chengdu.aliyuncs.com/img/学习页/课后/pad/pad状态栏和导航栏.png"
          alt="nav-status"
          className="w-full h-auto"
        />
      </div>

      {/* 主要内容区域 */}
      <div className="flex-1 px-[137px] flex flex-col gap-10 mt-5 overflow-y-auto">
        {/* Banner 广告图 */}
        <div className="w-full h-[112px] rounded-[10px] overflow-hidden flex-shrink-0">
          <img
            src={bannerImage}
            alt="banner"
            className="w-full h-full object-cover"
          />
        </div>

        {/* 服务内容 */}
        <div className="flex flex-col gap-6">
          {/* 标题区 */}
          <div className="flex items-center justify-between w-full">
            <span
              className="text-[22.5px] font-medium text-[#4d4d4d]"
              style={{ fontFamily: '"PingFang SC", sans-serif' }}
            >
              全年系统包-L1
            </span>
            <div className="flex items-center gap-[5px]">
              <span
                className="text-[17.5px] text-[#666666]"
                style={{ fontFamily: '"PingFang SC", sans-serif' }}
              >
                苹果指导师
              </span>
              <img
                src="https://uiweb.oss-cn-chengdu.aliyuncs.com/img/学习页/课后/指导师头像.png"
                alt="teacher"
                className="w-[30px] h-[30px] rounded-[11.25px]"
                style={{ backgroundColor: '#fcda00' }}
              />
            </div>
          </div>

          {/* 功能入口列表 - 两行布局 */}
          <div className="flex flex-col gap-5">
            {featureRows.map((row, rowIndex) => (
              <div key={rowIndex} className="flex gap-5 w-full">
                {row.map((feature, colIndex) => (
                  <div
                    key={colIndex}
                    className="h-20 bg-[#fff3eb] rounded-[22.5px] flex items-center justify-between px-[25px]"
                    style={{ flex: row.length === 1 ? '0 0 100%' : '0 0 calc(50% - 10px)' }}
                  >
                    <div className="flex items-center gap-[10px] flex-1 min-w-0">
                      <img
                        src={feature.icon}
                        alt=""
                        className="w-[45px] h-[45px] rounded-[13.125px] flex-shrink-0"
                      />
                      <span
                        className="text-[20px] font-medium text-[#6b2d03] truncate"
                        style={{ fontFamily: '"PingFang SC", sans-serif' }}
                      >
                        {feature.name}
                      </span>
                    </div>
                    <div className="flex items-center gap-[5px] flex-shrink-0 ml-2">
                      {feature.status && (
                        <span
                          className="text-[17.5px] text-[#e35b00] whitespace-nowrap"
                          style={{ fontFamily: '"PingFang SC", sans-serif' }}
                        >
                          {feature.status}
                        </span>
                      )}
                      <ChevronRight className="w-5 h-5 text-[#ffa66b]" />
                    </div>
                  </div>
                ))}
              </div>
            ))}
          </div>

          {/* 底部链接 */}
          <div className="flex items-center justify-center gap-1 mt-5">
            <span
              className="text-[17.5px] text-[#b2b2b2]"
              style={{ fontFamily: '"PingFang SC", sans-serif' }}
            >
              查看往期课程
            </span>
            <ChevronRight className="w-5 h-5 text-[#e0dfdf]" />
          </div>
        </div>
      </div>
    </div>
  );
}

